  ('pukao-6e11b43e-moex-00399', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-111-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '某道路橋樑之耐震設計不當，致大貨車通過時，橋樑崩塌斷裂壓傷甲，經送醫不治死亡。有關甲之國家賠 償，下列敘述何者錯誤？', '["賠償範圍包括醫藥費、喪葬費", "甲之配偶、子女得請求非財產上損害賠償", "賠償義務機關賠償後，不得對橋樑設計廠商求償", "甲之父親得請求相當於扶養費之損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "413", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00400', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-111-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於損失補償之敘述，下列何者錯誤？', '["人民因機關即時強制致財產損失，得請求補償", "損失補償原則上以金錢為之，並以實際損失為限", "不服損失補償之決定，得提起給付訴訟", "授予利益之違法行政處分遭撤銷，相對人主張信賴保護而請求損失補償遭拒，得提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "413", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00401', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '相較於私人企業，行政機關的制度特性之一是強調「層級節制」，下列何者最有可能是此一制度設計的考 量因素？', '["降低對於人民權利的傷害性", "提高組織任務分工的明確性", "減少政治與行政間的衝突性", "增加行政人員執法的合法性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "760de019782d", "answer_pdf_sha1": "17c34a568914", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00402', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '下列何者是從新公共管理的觀點來看行政？', '["行政的主要價值觀為社會公平", "決策制定採漸進主義", "組織的結構主義", "市場取向的預算制度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "760de019782d", "answer_pdf_sha1": "17c34a568914", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00403', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '有關行政學相關理論之敘述，下列何者錯誤？', '["邏輯實證論反對價值中立", "後邏輯實證論強調社會公平正義價值", "系統理論強調環境對組織的影響", "新公共服務認為公部門的課責並不容易"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "760de019782d", "answer_pdf_sha1": "17c34a568914", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00404', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-110-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '有關新公共管理與新公共服務論述之比較，下列何者正確？', '["前者服務對象是公民，後者服務對象是顧客", "前者奠基於民主理論，後者則植基於經濟理論", "前者強調政府作為導航者，後者強調政府作為提供服務者", "前者主張多面向途徑，後者主張以市場導向途徑為主"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "760de019782d", "answer_pdf_sha1": "17c34a568914", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
